const cp = require("child_process");
const url = $json.body.url;
if (!url || !url.includes("github.com")) return [{ json: { output: "❌ URL de GitHub inválida" } }];

const dir = "/tmp/repo_" + Date.now();
try {
  cp.execSync(`git clone --depth 1 ${url} ${dir}`);
  const mds = cp.execSync(`find ${dir} -maxdepth 3 -name "*.md" -exec cat {} + | head -c 20000`).toString();
  const packageJson = cp.execSync(`cat ${dir}/package.json 2>/dev/null || echo ""`).toString();
  const reqTxt = cp.execSync(`cat ${dir}/requirements.txt 2>/dev/null || echo ""`).toString();
  cp.execSync(`rm -rf ${dir}`);
  return [{ json: { output: `✅ Repo analizado:\n\n=== Dependencias JS ===\n${packageJson.substring(0, 500)}\n\n=== Dependencias Python ===\n${reqTxt.substring(0, 500)}\n\n=== Archivos Markdown (Extracto) ===\n${mds}` } }];
} catch(e) {
  try { cp.execSync(`rm -rf ${dir}`); } catch(err){}
  return [{ json: { output: `❌ Error analizando repo: ` + e.message } }];
}
